+
+	// Check ordering: Rules should come before Anti-Patterns, which should come before Snippets
+	rulesIdx := bytes.Index([]byte(formatted), []byte("Procedural Memory"))
+	antiIdx := bytes.Index([]byte(formatted), []byte("Anti-Patterns"))
