+	t.Logf("CM_CONTEXT_TEST: Operation=PriorityOrdering | RulesIdx=%d | AntiIdx=%d | SnippetsIdx=%d | Duration=%v",
+		rulesIdx, antiIdx, snippetsIdx, time.Since(start))
