+	seen := make(map[string]bool)
+	for _, code := range codes {
+		t.Run("Code_"+code, func(t *testing.T) {
+			// Verify format: UPPER_SNAKE_CASE
+			if code == "" {
+				t.Error("Error code should not be empty")
